 3	import { ConsoleTimestamp } from '@components/ConsoleTimestamp/ConsoleTimestamp';
 4	import SectionHeading from '@components/headers/SectionHeading';
 5	import type { IoK8sApiBatchV1Job } from '@kubev2v/types';
 6	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 8	import { JobModelGroupVersionKind } from '@utils/crds/common/models';
 9	import { getName, getNamespace, getUID } from '@utils/crds/common/selectors';
10	import { isEmpty } from '@utils/helpers';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import { getJobPhase } from '../../utils/utils';
14	
15	type MigrationJobsTableProps = {
16	  jobs: IoK8sApiBatchV1Job[];
17	};
18	
19	const MigrationJobsTable: FC<MigrationJobsTableProps> = ({ jobs }) => {
20	  const { t } = useForkliftTranslation();
21	
22	  if (isEmpty(jobs)) {
23	    return null;
24	  }
25	
26	  return (
27	    <>
28	      <SectionHeading
29	        className="migration-status-expanded-page__resource-list-header"
30	        textComponent="h3"
31	        text={t('Jobs')}
32	      />
33	      <Table>
34	        <Thead>
35	          <Tr>
36	            <Th width={40}>{t('Name')}</Th>
37	            <Th width={20}>{t('Description')}</Th>
38	            <Th>{t('Completed at')}</Th>
39	          </Tr>
40	        </Thead>
41	        <Tbody>
42	          {jobs.map((job) => (
43	            <Tr key={getUID(job)}>
44	              <Td width={40}>
45	                <ResourceLink
46	                  groupVersionKind={JobModelGroupVersionKind}
47	                  name={getName(job)}
48	                  namespace={getNamespace(job)}
49	                />
50	              </Td>
51	              <Td width={20}>{getJobPhase(job)}</Td>
52	              <Td>
53	                <ConsoleTimestamp
54	                  timestamp={job?.status?.completionTime ?? null}
55	                  showGlobalIcon={false}
56	                />
57	              </Td>
58	            </Tr>
59	          ))}
60	        </Tbody>
61	      </Table>
62	    </>
63	  );
64	};
65	
66	export default MigrationJobsTable;

